-- Hungary – Student Residence Permit (National D Visa) — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee student visa approval?","a":"No. Embassy decides based on admission, funds, and credibility. Never promise approval."},{"q":"What is proof of funds for Hungary?","a":"Typically HUF living funds per OIF guidelines months (HUF benchmark/year) living funds or equivalent. Verify current amount on oif.gov.hu before quoting."},{"q":"Proof of funds amount for 2026?","a":"Typically HUF living funds per OIF guidelines (HUF benchmark/year). Verify current amount on oif.gov.hu before quoting."},{"q":"Can spouse accompany?","a":"Dependants may apply separately; prove additional funds and accommodation. Assess case-by-case."},{"q":"English-taught programs need Hungarian?","a":"Depends on program—follow admission and embassy requirements."},{"q":"How long to convert to residence permit?","a":"Apply at Migration Department (oif.gov.hu) soon after arrival and university registration."},{"q":"Can I work on student visa?","a":"Limited working hours permitted—verify current rules for students in Hungary."},{"q":"What after graduation?","a":"Discuss Graduate job-search temporary residence permit (verify on oif.gov.hu) separately."},{"q":"What is Description for this service?","a":"National visa (Type D) for study at a recognised Hungarian university. After entry, apply for temporary residence permit at Migration Department (oif.gov.hu)."},{"q":"What is Eligible applicants for this service?","a":"University admission letter · Proof of funds (HUF living funds per OIF guidelines) · Health insurance · Motivation letter · Valid passport · Language proficiency as required"},{"q":"What is Proof of funds for this service?","a":"HUF living funds per OIF guidelines months (HUF benchmark/year) typically required unless scholarship or sponsor alternative applies."},{"q":"Important note on Proof of funds?","a":"HUF living funds per OIF guidelines months (HUF benchmark/year) typically required unless scholarship or sponsor alternative applies."},{"q":"What is Key authority for this service?","a":"Hungarian Embassy/Consulate in India · VFS Global Hungary · Migration Department (oif.gov.hu) after arrival"},{"q":"What is After approval for this service?","a":"Enter Hungary; register address; apply for temporary residence permit at Migration Department (oif.gov.hu) within visa validity."},{"q":"Is Admission from recognised Hungarian institution required?","a":"Admission from recognised Hungarian institution is typically required."},{"q":"Is Proof of funds (HUF living funds per OIF guidelines) required?","a":"Apply early—processing takes weeks"},{"q":"Is Proof of funds or financial proof required?","a":"HUF benchmark/year or equivalent with 3–6 month bank history"},{"q":"Is Health insurance (travel + statutory) required?","a":"Assess whether Health insurance (travel + statutory) is satisfied for this case."},{"q":"Is Motivation letter and CV required?","a":"Motivation letter and CV is typically required."},{"q":"Is Language proficiency (as required) required?","a":"Hungarian or English per program"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"What is the Processing time?","a":"6–12w — After complete file complete"},{"q":"What is the Government fee?","a":"€75 — + proof of funds required living funds"},{"q":"What is the Our approval rate?","a":"88% — ~74% benchmark"},{"q":"What is the Required docs?","a":"15 — + proof of funds HUF benchmark"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has Proof of funds insufficient?","a":"Open blocked account or show HUF benchmark equivalent with 3–6 month bank history before embassy slot"},{"q":"Why is Proof of funds insufficient a problem?","a":"Proof of funds below HUF living funds per OIF guidelines or inconsistent bank history."},{"q":"What if the client has Insufficient proof of funds?","a":"Open proof of funds at approved bank for full required amount"},{"q":"Why is Insufficient proof of funds a problem?","a":"Amount below required monthly sum or not from recognised provider."}]'::jsonb
), updated_at = now()
